"use strict";(self.webpackChunkastrology_garden=self.webpackChunkastrology_garden||[]).push([["5339"],{318(e,n,i){i.r(n),i.d(n,{metadata:()=>a,default:()=>p,frontMatter:()=>t,contentTitle:()=>r,toc:()=>l,assets:()=>c});var a=JSON.parse('{"id":"Stellar bodies/neptune","title":"neptune","description":"Principle:","source":"@site/docs/Stellar bodies/neptune.md","sourceDirName":"Stellar bodies","slug":"/Stellar bodies/neptune","permalink":"/docs/Stellar bodies/neptune","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/Stellar bodies/neptune.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"moon","permalink":"/docs/Stellar bodies/moon"},"next":{"title":"node","permalink":"/docs/Stellar bodies/node"}}'),o=i(4848),s=i(8453);let t={},r,c={},l=[{value:"T\u0142umaczenie na j\u0119zyk polski (Translation)",id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",level:3}];function d(e){let n={h3:"h3",li:"li",p:"p",ul:"ul",...(0,s.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(n.p,{children:"Principle:"}),"\n",(0,o.jsx)(n.p,{children:"Receptivity, impressionability, a sympathetic understanding of people."}),"\n",(0,o.jsx)(n.p,{children:"Psychological Correspondence:"}),"\n",(0,o.jsxs)(n.ul,{children:["\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"Receptivity, fantasy or imagination, sensitivity, contemplation, sympathetic understanding or compassionate sensitivity, a dreamy nature, an inclination to mysticism, mediumism."}),"\n"]}),"\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"Impressionability, sensitiveness, vagueness or confusion, fanciful notions, deception, a lack of clarity, lack of planning ability, a lie or a fraud."}),"\n"]}),"\n"]}),"\n",(0,o.jsx)(n.p,{children:"Biological Correspondence:"}),"\n",(0,o.jsx)(n.p,{children:"The pineal gland, the solar plexus, the aura \u2013 slackness or laxity, paralysis."}),"\n",(0,o.jsx)(n.p,{children:"Sociological Correspondence:"}),"\n",(0,o.jsx)(n.p,{children:"People with a negative outlook on life who are easily influenced by other persons, mediums, persons of doubtful character, crooks or tricksters."}),"\n",(0,o.jsx)(n.p,{children:"Positions in Houses and Signs:"}),"\n",(0,o.jsx)(n.p,{children:"I. The realisation of inspirations, unselfishness, a love of humanity, a delicate and highly sensitive nervous system, a nature richly expressing the whole gamut of feelings, a longing for seeing far distant countries, ideas concerning the social welfare. \u2013 Hypersensitiveness, confusion, a person without aims or objectives, insane and mad ideas."}),"\n",(0,o.jsx)(n.p,{children:"II. A moody person, good taste, the ability for creative designing, a sense of shape or form, a sense of tact, strange sources of income. \u2013 Partiality for alcohol, nicotine, etc., the absence of good taste, a lack of endurance and stamina, ill luck in speculation."}),"\n",(0,o.jsx)(n.p,{children:"III. Impressionability, the faculty to understand others with one's sensitive nature, fantasy and imagination, the faculty to become inspired at times, a love of nature, mystic tendencies and aspirations. \u2013 A dual nature, a confused imagination, a lack of clarity, wrong ideas about other people, a weak memory."}),"\n",(0,o.jsx)(n.p,{children:"IV. Sensitiveness, the growth of spiritual perception, a deeply feeling nature, an affectionate nature, the feeling of an inner union with others. \u2013 Melancholy, an unstable character, hypersensitiveness, soul-suffering through disappointments."}),"\n",(0,o.jsx)(n.p,{children:"V. An abundance of plans, enthusiasm, many wishes, a love of beauty and art, the ability to act, also to put on an act. \u2013 The tendency to exaggerate, wastefulness, self-glorification, misdirected passion, seduction."}),"\n",(0,o.jsx)(n.p,{children:"VI. An intuitive understanding of other people, a person interested in the art and science of healing, magnetic healing powers, a union between intellect and inspiration, planning. \u2013 A pathological sensitiveness, nagging or fault-finding, difficulties when working together with other people."}),"\n",(0,o.jsx)(n.p,{children:"VII. A receptive nature, the expression of the finer feelings in love, high ideals. Being an active and integral part of an association or community, platonic love. \u2013 Being unrealistic can lead to disappointment or error; odd relation of self to the public."}),"\n",(0,o.jsx)(n.p,{children:"VIII. The stirrings within the subconscious, instinctive comprehension, keen senses, mediumistic faculties, a person interested in metapsychical subjects. \u2013 States of depression, wrong doing, states of sickness within the soul or within the mind as distinct from physical suffering or illness."}),"\n",(0,o.jsx)(n.p,{children:"IX. The faculty of presentiment, the inclination to ponder over something, the striving for the attainment of higher knowledge, a great deal of wishes and plans, an active mind, inspiration. \u2013 An over-active imagination, self-deception through lack of discrimination."}),"\n",(0,o.jsx)(n.p,{children:'X. The ability to conduct research deeply and thoroughly, the flair for the "Supernatural", meditation, the inclination to delve into religious problems, strange objectives. \u2013 The attainment of one\'s objectives by crooked means, a person lacking a love of truth and sense of reality.'}),"\n",(0,o.jsx)(n.p,{children:"XI. Strange powers of attraction, the search for soul-unions, a person with hopes and wishes, noble aims and aspirations, mind and spirit capable of change. \u2013 Insincerity, fraud, a person who is influenced easily by other people, easy yielding to temptation."}),"\n",(0,o.jsx)(n.p,{children:"XII. Reserve, an inclination to mysticism, reverie and artistic pursuits. \u2013 The inner or psychic life is open to external influences, pessimism, a craving for alcohol, nicotine, etc., pathological tendencies and inclinations."}),"\n",(0,o.jsx)(n.h3,{id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",children:"T\u0142umaczenie na j\u0119zyk polski (Translation)"}),"\n",(0,o.jsx)(n.p,{children:"NEPTUN"}),"\n",(0,o.jsx)(n.p,{children:"Zasada:"}),"\n",(0,o.jsx)(n.p,{children:"Receptywno\u015B\u0107, podatno\u015B\u0107 na wra\u017Cenia, pe\u0142ne empatii rozumienie ludzi."}),"\n",(0,o.jsx)(n.p,{children:"Korespondencja psychologiczna:"}),"\n",(0,o.jsxs)(n.ul,{children:["\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"Receptywno\u015B\u0107, fantazja lub wyobra\u017Ania, wra\u017Cliwo\u015B\u0107, kontemplacja, pe\u0142ne empatii rozumienie lub wsp\xf3\u0142czuj\u0105ca wra\u017Cliwo\u015B\u0107, marzycielska natura, sk\u0142onno\u015B\u0107 do mistycyzmu, mediumizm."}),"\n"]}),"\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"Podatno\u015B\u0107 na wra\u017Cenia, nadwra\u017Cliwo\u015B\u0107, mglisto\u015B\u0107 lub pomieszanie, fantazyjne wyobra\u017Cenia, oszustwo, brak jasno\u015Bci, brak zdolno\u015Bci planowania, k\u0142amstwo lub oszustwo."}),"\n"]}),"\n"]}),"\n",(0,o.jsx)(n.p,{children:"Korespondencja biologiczna:"}),"\n",(0,o.jsx)(n.p,{children:"Szyszynka, splot s\u0142oneczny, aura \u2013 wiotko\u015B\u0107 lub rozlu\u017Anienie, parali\u017C."}),"\n",(0,o.jsx)(n.p,{children:"Korespondencja socjologiczna:"}),"\n",(0,o.jsx)(n.p,{children:"Ludzie o negatywnym spojrzeniu na \u017Cycie, kt\xf3rzy \u0142atwo ulegaj\u0105 wp\u0142ywom innych os\xf3b, media, osoby o w\u0105tpliwym charakterze, kanciarze lub oszu\u015Bci."}),"\n",(0,o.jsx)(n.p,{children:"Pozycje w domach i znakach:"}),"\n",(0,o.jsx)(n.p,{children:"I. Realizacja inspiracji, bezinteresowno\u015B\u0107, mi\u0142o\u015B\u0107 do ludzko\u015Bci, delikatny i wysoce wra\u017Cliwy uk\u0142ad nerwowy, natura bogato wyra\u017Caj\u0105ca ca\u0142\u0105 gam\u0119 uczu\u0107, t\u0119sknota za ogl\u0105daniem dalekich kraj\xf3w, idee dotycz\u0105ce opieki spo\u0142ecznej. \u2013 Nadwra\u017Cliwo\u015B\u0107, pomieszanie, osoba bez cel\xf3w lub d\u0105\u017Ce\u0144, ob\u0142\u0105ka\u0144cze i szalone pomys\u0142y."}),"\n",(0,o.jsx)(n.p,{children:"II. Osoba kapry\u015Bna (ulegaj\u0105ca nastrojom), dobry gust, zdolno\u015B\u0107 do kreatywnego projektowania, zmys\u0142 kszta\u0142tu lub formy, zmys\u0142 taktu, dziwne \u017Ar\xf3d\u0142a dochodu. \u2013 S\u0142abo\u015B\u0107 do alkoholu, nikotyny itp., brak dobrego gustu, brak wytrwa\u0142o\u015Bci i odporno\u015Bci, nieszcz\u0119\u015Bcie w spekulacji."}),"\n",(0,o.jsx)(n.p,{children:"III. Podatno\u015B\u0107 na wra\u017Cenia, zdolno\u015B\u0107 rozumienia innych swoj\u0105 wra\u017Cliw\u0105 natur\u0105, fantazja i wyobra\u017Ania, zdolno\u015B\u0107 do okresowego wpadania w inspiracj\u0119, mi\u0142o\u015B\u0107 do natury, mistyczne tendencje i aspiracje. \u2013 Dualistyczna natura, zagmatwana wyobra\u017Ania, brak jasno\u015Bci, b\u0142\u0119dne wyobra\u017Cenia o innych ludziach, s\u0142aba pami\u0119\u0107."}),"\n",(0,o.jsx)(n.p,{children:"IV. Wra\u017Cliwo\u015B\u0107, wzrost duchowej percepcji, g\u0142\u0119boko czuj\u0105ca natura, czu\u0142e usposobienie, poczucie wewn\u0119trznej jedno\u015Bci z innymi. \u2013 Melancholia, niestabilny charakter, nadwra\u017Cliwo\u015B\u0107, cierpienie duszy z powodu rozczarowa\u0144."}),"\n",(0,o.jsx)(n.p,{children:"V. Obfito\u015B\u0107 plan\xf3w, entuzjazm, wiele \u017Cycze\u0144, zami\u0142owanie do pi\u0119kna i sztuki, zdolno\u015B\u0107 do dzia\u0142ania, a tak\u017Ce do udawania (odgrywania roli). \u2013 Tendencja do przesady, rozrzutno\u015B\u0107, samouwielbienie, \u017Ale ukierunkowana nami\u0119tno\u015B\u0107, uwiedzenie."}),"\n",(0,o.jsx)(n.p,{children:"VI. Intuicyjne rozumienie innych ludzi, osoba zainteresowana sztuk\u0105 i nauk\u0105 o uzdrawianiu, magnetyczne zdolno\u015Bci uzdrawiania, po\u0142\u0105czenie intelektu z inspiracj\u0105, planowanie. \u2013 Patologiczna wra\u017Cliwo\u015B\u0107, zrz\u0119dliwo\u015B\u0107 lub szukanie dziury w ca\u0142ym, trudno\u015Bci podczas wsp\xf3lnej pracy z innymi lud\u017Ami."}),"\n",(0,o.jsx)(n.p,{children:"VII. Receptywna natura, wyra\u017Canie subtelniejszych uczu\u0107 w mi\u0142o\u015Bci, wysokie idea\u0142y. Bycie aktywn\u0105 i integraln\u0105 cz\u0119\u015Bci\u0105 zwi\u0105zku lub spo\u0142eczno\u015Bci, mi\u0142o\u015B\u0107 platoniczna. \u2013 Bycie nierealistycznym mo\u017Ce prowadzi\u0107 do rozczarowania lub b\u0142\u0119du; dziwny stosunek w\u0142asnej osoby do og\xf3\u0142u (publiczno\u015Bci)."}),"\n",(0,o.jsx)(n.p,{children:"VIII. Poruszenia w pod\u015Bwiadomo\u015Bci, instynktowne pojmowanie, wyostrzone zmys\u0142y, zdolno\u015Bci mediumiczne, osoba zainteresowana tematami metapsychicznymi. \u2013 Stany depresyjne, z\u0142e post\u0119powanie, stany chorobowe w duszy lub w umy\u015Ble jako odr\u0119bne od fizycznego cierpienia lub choroby."}),"\n",(0,o.jsx)(n.p,{children:"IX. Zdolno\u015B\u0107 przeczuwania, sk\u0142onno\u015B\u0107 do rozmy\u015Blania nad czym\u015B, d\u0105\u017Cenie do osi\u0105gni\u0119cia wy\u017Cszej wiedzy, bardzo wiele \u017Cycze\u0144 i plan\xf3w, aktywny umys\u0142, inspiracja. \u2013 Nadmiernie aktywna wyobra\u017Ania, oszukiwanie samego siebie z powodu braku rozeznania."}),"\n",(0,o.jsx)(n.p,{children:"X. Zdolno\u015B\u0107 do prowadzenia bada\u0144 g\u0142\u0119boko i dok\u0142adnie, zami\u0142owanie do \u201ENadprzyrodzonego\u201D, medytacja, sk\u0142onno\u015B\u0107 do zag\u0142\u0119biania si\u0119 w problemy religijne, dziwne cele. \u2013 Osi\u0105ganie swoich cel\xf3w nieuczciwymi sposobami, osoba pozbawiona umi\u0142owania prawdy i poczucia rzeczywisto\u015Bci."}),"\n",(0,o.jsx)(n.p,{children:"XI. Dziwne moce przyci\u0105gania, poszukiwanie jedno\u015Bci dusz, osoba z nadziejami i \u017Cyczeniami, szlachetne cele i aspiracje, umys\u0142 i duch zdolne do zmian. \u2013 Nieszczero\u015B\u0107, oszustwo, osoba, na kt\xf3r\u0105 inni ludzie \u0142atwo wywieraj\u0105 wp\u0142yw, \u0142atwe uleganie pokusom."}),"\n",(0,o.jsx)(n.p,{children:"XII. Rezerwa, sk\u0142onno\u015B\u0107 do mistycyzmu, marzycielstwo i zaj\u0119cia artystyczne. \u2013 \u017Bycie wewn\u0119trzne lub psychiczne jest otwarte na wp\u0142ywy zewn\u0119trzne, pesymizm, \u0142aknienie alkoholu, nikotyny itp., patologiczne tendencje i sk\u0142onno\u015Bci."})]})}function p(e={}){let{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,o.jsx)(n,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},8453(e,n,i){i.d(n,{R:()=>t,x:()=>r});var a=i(6540);let o={},s=a.createContext(o);function t(e){let n=a.useContext(s);return a.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:t(e.components),a.createElement(s.Provider,{value:n},e.children)}}}]);